CustomField.formula:
IF(
    Overall_Scores__c > 90, "A+",
    IF(
        Overall_Scores__c >= 80, "A",
        IF(
            Overall_Scores__c >= 70, "B+",
            IF(
                Overall_Scores__c >= 60, "B",
                IF(
                    Overall_Scores__c >= 50, "C",
                    "F"
                )
            )
        )
    )
)
